1	package agent
2	
3	import (
4		"context"
5		"fmt"
6		"os"
7		"path/filepath"
8		"sort"
9		"strings"
10	
11		"github.com/DocumentDrivenDX/ddx/internal/config"
12		internalgit "github.com/DocumentDrivenDX/ddx/internal/git"
13		agentlib "github.com/easel/fizeau"
14	)
15	
16	const (
17		// Lifecycle classifiers run in an isolated scratch workdir and are guarded by
18		// a project-root dirtiness check. Use Fizeau's supported safe permission band
19		// so unpinned auto-routing can choose a route; the reviewer path keeps the
20		// stricter internal readonly marker.
21		PermissionsReadOnlyLifecycle = "safe"
22		lifecycleScratchDirPrefix    = "ddx-lifecycle-"
23	)
24	
25	type lifecycleProjectStatusSnapshot struct {
26		available bool
27		entries   map[string]string
28	}
29	
30	func dispatchLifecycleRun(ctx context.Context, projectRoot string, svc agentlib.FizeauService, runner AgentRunner, rcfg config.ResolvedConfig, runtime AgentRunRuntime) (*Result, error) {
31		scratchDir, err := newLifecycleScratchDir(projectRoot)
32		if err != nil {
33			return nil, fmt.Errorf("lifecycle dispatch: create scratch workdir: %w", err)
34		}
35		defer func() {
36			// Deregister the seeded worktree (no-op/ignored if the fallback empty
37			// repo was used) before removing the directory, so it does not linger
38			// in the project's worktree registry.
39			_ = internalgit.Command(context.Background(), projectRoot, "worktree", "remove", "--force", scratchDir).Run()
40			_ = os.RemoveAll(scratchDir)
41		}()
42	
43		runtime.WorkDir = scratchDir
44		runtime.PermissionsOverride = PermissionsReadOnlyLifecycle
45	
46		before, err := captureLifecycleProjectStatus(projectRoot)
47		if err != nil {
48			return nil, err
49		}
50	
51		result, dispatchErr := dispatchViaResolvedConfig(ctx, projectRoot, svc, runner, rcfg, runtime)
52	
53		if guardErr := guardLifecycleProjectStatus(projectRoot, before); guardErr != nil {
54			return nil, guardErr
55		}
56		if dispatchErr != nil {
57			return nil, dispatchErr
58		}
59		return result, nil
60	}
61	
62	func newLifecycleScratchDir(projectRoot string) (string, error) {
63		dir, err := config.MkdirExecutionScratch(projectRoot, lifecycleScratchDirPrefix)
64		if err != nil {
65			return "", err
66		}
67		// Seed the scratch workdir from the project's HEAD so the readiness-check
68		// classifier sees the project's real source files rather than an empty repo
69		// — otherwise file-presence checks block every bead (ddx-efadca32). A
70		// detached worktree keeps the classifier isolated from the master worktree
71		// (it cannot mutate tracked files there). git worktree add must create the
72		// directory itself, so clear the placeholder MkdirExecutionScratch made.
73		if rmErr := os.RemoveAll(dir); rmErr != nil {
74			return "", fmt.Errorf("reset lifecycle scratch dir: %w", rmErr)
75		}
76		if out, addErr := internalgit.Command(context.Background(), projectRoot, "worktree", "add", "--detach", dir, "HEAD").CombinedOutput(); addErr != nil {
77			// HEAD may be unborn (a project with no commits yet); readiness has
78			// nothing to check there, so fall back to an empty scratch repo.
79			if mkErr := os.MkdirAll(dir, 0o700); mkErr != nil {
80				return "", fmt.Errorf("recreate lifecycle scratch dir after worktree add failed (%s): %w", strings.TrimSpace(string(out)), mkErr)
81			}
82			if out2, initErr := internalgit.Command(context.Background(), dir, "init", "-q").CombinedOutput(); initErr != nil {
83				_ = os.RemoveAll(dir)
84				return "", fmt.Errorf("initialize lifecycle scratch git repo: %s: %w", strings.TrimSpace(string(out2)), initErr)
85			}
86		}
87		return dir, nil
88	}
