21	func prepareExecuteBeadGitIsolation(projectRoot, wtPath, stateDir string) (map[string]string, error) {
22		if err := enableExecuteBeadWorktreeConfig(projectRoot); err != nil {
23			return nil, err
24		}
25		if !sameFilesystemPath(projectRoot, wtPath) {
26			_ = enableExecuteBeadWorktreeConfig(wtPath)
27		}
28	
29		worktreeGitDir, err := executeBeadWorktreeGitDir(wtPath)
30		if err != nil {
31			return nil, err
32		}
33		if err := seedExecuteBeadWorktreeConfig(projectRoot, worktreeGitDir); err != nil {
34			return nil, err
35		}
36	
37		if err := os.MkdirAll(stateDir, 0o755); err != nil {
38			return nil, fmt.Errorf("creating execute-bead git isolation dir: %w", err)
39		}
40		wrapperDir := filepath.Join(stateDir, executeBeadGitWrapperDirName)
41		if err := os.MkdirAll(wrapperDir, 0o755); err != nil {
42			return nil, fmt.Errorf("creating execute-bead git wrapper dir: %w", err)
43		}
44	
45		privateCfg := filepath.Join(stateDir, executeBeadGitPrivateConfigName)
46		if err := ensureExecuteBeadPrivateConfig(privateCfg); err != nil {
47			return nil, err
48		}
49		globalCfg := filepath.Join(stateDir, executeBeadGitGlobalConfigFileName)
50		if err := ensureExecuteBeadPrivateConfig(globalCfg); err != nil {
51			return nil, err
52		}
53	
54		realGit, err := exec.LookPath("git")
55		if err != nil {
56			return nil, fmt.Errorf("resolving git binary for execute-bead wrapper: %w", err)
57		}
58		wrapperPath := filepath.Join(wrapperDir, executeBeadGitWrapperFileName)
59		if err := os.WriteFile(wrapperPath, []byte(renderExecuteBeadGitWrapper(realGit, privateCfg)), 0o755); err != nil {
60			return nil, fmt.Errorf("writing execute-bead git wrapper: %w", err)
61		}
62	
63		env := map[string]string{
64			"PATH":              wrapperDir + string(os.PathListSeparator) + os.Getenv("PATH"),
65			"GIT_CONFIG_GLOBAL": globalCfg,
66			"GIT_CONFIG_SYSTEM": "/dev/null",
67		}
68		return env, nil
69	}
