71	func sanitizeExecuteBeadWorktreeConfig(wtPath string) {
72		for _, key := range []string{"core.bare", "core.worktree"} {
73			_ = internalgit.Command(context.Background(), wtPath, "config", "--worktree", "--unset-all", key).Run()
