50		projectRoot := t.TempDir()
51		require.NoError(t, os.MkdirAll(filepath.Join(projectRoot, ddxroot.DirName), 0o755))
52		require.NoError(t, os.WriteFile(filepath.Join(projectRoot, ddxroot.DirName, "beads.jsonl"), []byte("{}\n"), 0o644))
53	
54		tempRoot := t.TempDir()
55		t.Setenv("DDX_EXEC_WT_DIR", tempRoot)
56	
57		gitOps := &worktreeAddFailGitOps{baseRev: "base123"}
58		rcfg := config.NewTestConfigForBead(config.TestBeadConfigOpts{}).Resolve(config.CLIOverrides{})
59	
60		res, err := ExecuteBeadWithConfig(context.Background(), projectRoot, "ddx-worktree-cleanup", rcfg, ExecuteBeadRuntime{}, gitOps)
61		// A disk-exhaustion worktree-add failure now surfaces as a
62		// resource_exhausted result (not a raw error) so the execute-loop releases
63		// the claim instead of leaving the bead claimed-but-open (ddx-f677a50b).
64		// The partial worktree dir must still be cleaned up.
65		require.NoError(t, err)
66		require.NotNil(t, res)
67		assert.Equal(t, ExecuteBeadStatusResourceExhausted, res.Status)
68		assert.NotEmpty(t, gitOps.addedPath)
69		assert.Empty(t, gitOps.removedPath)
70		assert.NoFileExists(t, gitOps.addedPath)
71	}
