package agent

import (
	"context"
	"encoding/json"
	"os"
	"path/filepath"
	"strings"
	"sync/atomic"
	"testing"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/bead"
	"github.com/DocumentDrivenDX/ddx/internal/config"
	"github.com/DocumentDrivenDX/ddx/internal/ddxroot"
	"github.com/DocumentDrivenDX/ddx/internal/agent/executeloop"
	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
)

// TestFailedAttemptLeavesCanonicalCleanAndEscalationGetsFreshWorktree pins the
// AC #1 contract for routing P0 (ddx-2a24727c): a failed attempt must leave the
// canonical checkout clean, and the escalation retry (a re-entry of
// ExecuteBeadWithConfig with a fresh attempt ID) must start from a clean,
// isolated worktree distinct from the failed attempt's.
//
// The worktree attempt backend is the production default (ResolveAttemptBackend
// returns it for the empty config). Each attempt ID maps to its own worktree
// path via executeBeadWorktreePath, so an escalation retry — which generates a
// new attempt ID — never reuses the failed attempt's dirty worktree, and the
// deferred Cleanup() removes the failed worktree with `git worktree remove
// --force` so nothing leaks into the canonical checkout.
func TestFailedAttemptLeavesCanonicalCleanAndEscalationGetsFreshWorktree(t *testing.T) {
	root, _ := newScriptHarnessRepo(t, 1)
	beadID := "ddx-int-0001"

	backend, err := ResolveAttemptBackend(config.NewTestConfigForLoop(config.TestLoopConfigOpts{}).Resolve(config.CLIOverrides{}))
	require.NoError(t, err)
	require.Equal(t, AttemptBackendWorktree, backend.Name(), "production default backend must isolate every attempt in its own worktree")

	gitOps := &RealGitOps{}
	baseRev := runGitInteg(t, root, "rev-parse", "HEAD")

	// Snapshot the canonical working-tree state before any attempt runs so we can
	// prove the failed attempt introduces no new canonical dirt.
	statusBefore, err := runGitIntegOutput(root, "status", "--porcelain")
	require.NoError(t, err)

	ctx := context.Background()

	// --- Attempt 1: simulate a failed attempt that dirtied its own worktree. ---
	ws1, err := backend.Prepare(ctx, AttemptBackendPrepareRequest{
		ProjectRoot: root,
		BeadID:      beadID,
		AttemptID:   "att-fail-0001",
		BaseRev:     baseRev,
		GitOps:      gitOps,
	})
	require.NoError(t, err)
	require.NotNil(t, ws1)
	require.Equal(t, executeBeadWorktreePath(root, beadID, "att-fail-0001"), ws1.WorkDir)
	require.DirExists(t, ws1.WorkDir)

	// A failing agent typically leaves half-written implementation files behind in
	// its isolated worktree. Those must never reach the canonical checkout.
	require.NoError(t, os.WriteFile(filepath.Join(ws1.WorkDir, "half_written.go"), []byte("package broken\n"), 0o644))
	require.NoError(t, os.WriteFile(filepath.Join(ws1.WorkDir, "seed.txt"), []byte("clobbered by failed attempt\n"), 0o644))

	require.NoError(t, backend.Cleanup(ctx, ws1))
	assert.NoDirExists(t, ws1.WorkDir, "failed attempt worktree must be removed on cleanup")

	statusAfterFail, err := runGitIntegOutput(root, "status", "--porcelain")
	require.NoError(t, err)
	assert.Equal(t, statusBefore, statusAfterFail, "a failed attempt must leave the canonical checkout clean")
	assert.Equal(t, baseRev, runGitInteg(t, root, "rev-parse", "HEAD"), "a failed attempt must not move the canonical HEAD")

	// --- Attempt 2: escalation retry re-enters with a fresh attempt ID. ---
	ws2, err := backend.Prepare(ctx, AttemptBackendPrepareRequest{
		ProjectRoot: root,
		BeadID:      beadID,
		AttemptID:   "att-escalate-0002",
		BaseRev:     baseRev,
		GitOps:      gitOps,
	})
	require.NoError(t, err)
	require.NotNil(t, ws2)
	t.Cleanup(func() { _ = backend.Cleanup(context.Background(), ws2) })

	assert.NotEqual(t, ws1.WorkDir, ws2.WorkDir, "escalation retry must use a distinct isolated worktree")
	require.DirExists(t, ws2.WorkDir)

	escalationStatus, err := runGitIntegOutput(ws2.WorkDir, "status", "--porcelain")
	require.NoError(t, err)
	assert.Empty(t, escalationStatus, "escalation retry must start from a clean isolated worktree")
	assert.NoFileExists(t, filepath.Join(ws2.WorkDir, "half_written.go"), "escalation worktree must not inherit the failed attempt's dirt")
	assert.Equal(t, baseRev, runGitInteg(t, ws2.WorkDir, "rev-parse", "HEAD"), "escalation retry must be checked out at the clean base revision")
}

// TestWorkerRefusesDirtyWIPRootWithoutChurn reproduces the helix-style dirty-WIP
// churn (AC #2 + AC #3 for ddx-2a24727c) end-to-end: a real ddx-initialized repo
// with uncommitted implementation WIP, a queue of several ready beads, and the
// real ExecuteBeadWithConfig pre-dispatch checkpoint driving the refusal.
//
// Before this contract was pinned, a dirty/WIP root would let the worker claim
// each ready bead in turn — churning the queue with repeated claim/refuse
// cycles. The worker must instead stop after the first refusal with a clear
// operator-attention signal and leave the remaining queue untouched.
func TestWorkerRefusesDirtyWIPRootWithoutChurn(t *testing.T) {
	root, _ := newScriptHarnessRepo(t, 3)

	// Uncommitted implementation WIP on the canonical checkout. "payments.go" is
	// not a DDx bookkeeping path, so the pre-dispatch checkpoint classifies it as
	// blocked implementation dirt and refuses to absorb it.
	require.NoError(t, os.WriteFile(filepath.Join(root, "payments.go"), []byte("package wip\n"), 0o644))

	dirFile := filepath.Join(t.TempDir(), "directive.txt")
	writeDirectiveFile(t, dirFile, []string{"commit test: must-not-run"})

	inner := bead.NewStore(ddxroot.JoinProject(root))
	store := &claimCountingStore{Store: inner}

	runner := NewRunner(Config{})
	gitOps := &RealGitOps{}
	rcfg := config.NewTestConfigForBead(config.TestBeadConfigOpts{Model: dirFile}).
		Resolve(config.CLIOverrides{Harness: "script"})

	var execCalls int32
	worker := &ExecuteBeadWorker{
		Store: store,
		// Drive the genuine pre-dispatch checkpoint: the refusal error is produced
		// by checkpointPreDispatchDirt seeing the real dirty WIP, not a hand-rolled
		// marker string.
		Executor: ExecuteBeadExecutorFunc(func(ctx context.Context, beadID string) (ExecuteBeadReport, error) {
			atomic.AddInt32(&execCalls, 1)
			_, err := ExecuteBeadWithConfig(ctx, root, beadID, rcfg, ExecuteBeadRuntime{AgentRunner: runner}, gitOps)
			if err != nil {
				return ExecuteBeadReport{
					BeadID: beadID,
					Status: ExecuteBeadStatusExecutionFailed,
					Detail: err.Error(),
				}, err
			}
			return ExecuteBeadReport{BeadID: beadID, Status: ExecuteBeadStatusSuccess}, nil
		}),
	}

	var logBuf, eventSink bufferSyncWriter
	cfgOpts := config.TestLoopConfigOpts{Assignee: "worker"}
	loopCfg := config.NewTestConfigForLoop(cfgOpts).Resolve(config.TestLoopOverrides(cfgOpts))

	// A drain that churns would still terminate (it would just exhaust the queue),
	// so the timeout is only a backstop against an unexpected infinite loop; the
	// no-churn guarantee is proved by execCalls/claimCalls below.
	ctx, cancel := context.WithTimeout(context.Background(), 60*time.Second)
	defer cancel()

	result, err := worker.Run(ctx, loopCfg, ExecuteBeadLoopRuntime{
		Mode:        executeloop.ModeDrain,
		Log:         &logBuf,
		EventSink:   &eventSink,
		ProjectRoot: root,
		SessionID:   "sess-dirty-wip",
		WorkerID:    "worker-dirty-wip",
	})
	require.NoError(t, err, "operator-attention stop must be a clean loop exit, not a context timeout")
	require.NotNil(t, result)

	// Operator-attention signal, not a silent stop.
	require.NotNil(t, result.OperatorAttention, "a dirty/WIP root must raise operator attention")
	assert.Equal(t, "checkpoint_dirty", result.OperatorAttention.Reason)
	assert.Equal(t, root, result.OperatorAttention.ProjectRoot)
	assert.Contains(t, result.OperatorAttention.DirtyPaths, "payments.go")
	assert.Equal(t, "OperatorAttention", result.StopCondition)
	assert.Equal(t, "operator_attention", result.ExitReason)

	// No churn: only the first ready bead reaches the executor / is claimed; the
	// rest of the queue is left untouched for the operator.
	assert.Equal(t, int32(1), atomic.LoadInt32(&execCalls), "a dirty/WIP root must stop the drain after the first refusal, not churn the queue")
	assert.Equal(t, int32(1), atomic.LoadInt32(&store.claimCalls), "the worker must not claim further beads once the dirty root is detected")

	for _, id := range []string{"ddx-int-0001", "ddx-int-0002", "ddx-int-0003"} {
		got, getErr := store.Get(id)
		require.NoError(t, getErr)
		assert.Equal(t, bead.StatusOpen, got.Status, "%s must remain open after a no-churn dirty-root stop", id)
		assert.Empty(t, got.Owner, "%s must not stay claimed after a no-churn dirty-root stop", id)
	}

	// The dirty WIP is left in place: cleanup is the operator's job, the worker
	// must not silently absorb or discard it.
	assert.FileExists(t, filepath.Join(root, "payments.go"), "worker must not delete the operator's WIP")

	// The operator-attention event is surfaced on the structured sink exactly once.
	var operatorAttentionEvents int
	for _, line := range strings.Split(strings.TrimSpace(eventSink.String()), "\n") {
		if strings.TrimSpace(line) == "" {
			continue
		}
		var entry map[string]any
		require.NoError(t, json.Unmarshal([]byte(line), &entry))
		if entry["type"] != "loop.operator_attention" {
			continue
		}
		data, ok := entry["data"].(map[string]any)
		require.True(t, ok)
		assert.Equal(t, "checkpoint_dirty", data["reason"])
		operatorAttentionEvents++
	}
	assert.Equal(t, 1, operatorAttentionEvents, "exactly one operator-attention event must be emitted for the dirty root")
}
